#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a))
using namespace std;
const int N=1e5+5,M=2e5+5,INF=0x3f3f3f3f;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline short Get(){char ch;do ch=getchar();while(ch<'A'||ch>'C');return ch-'A';}
struct Graph{int head[M],des[M],nxt[M],cnt;inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}}a;
struct Tarjan{int low,dfn,scc;}t[N];int stk[N],top,typ[N],loc[9],q,a1[N],a2[N],X[N],Y[N],n,d,m,dep,cnt,ans[N];bool iss[N],b1,b2,lis[9],got;char ch[N],c1,c2;
inline void tarjan(int u)
{
	t[u].dfn=t[u].low=++dep;iss[stk[++top]=u]=1;grep(a,u,i)
	{
		int v=a.des[i];if(!t[v].dfn)tarjan(v),t[u].low=min(t[u].low,t[v].low);
		else if(iss[v])t[u].low=min(t[u].low,t[v].dfn);
	}
	if(t[u].low==t[u].dfn){int v;++cnt;do{iss[v=stk[top--]]=0;t[v].scc=cnt;}while(v!=u);}
}
inline void Solve()
{
	a.cnt=cnt=0;Clear(a.head);Clear(t);rep(1,d,i)typ[loc[i]]=lis[i];rep(1,m,i)
	{
		if(typ[a1[i]]==X[i])continue;
		if(typ[a2[i]]==Y[i]){if((typ[a1[i]]+1)%3==X[i])a.ins(a1[i],a1[i]+n);else a.ins(a1[i]+n,a1[i]);continue;}
		b1=(X[i]==(typ[a1[i]]+2)%3);b2=(Y[i]==(typ[a2[i]]+2)%3);
//		printf("%d : %d %d %d %d %d %d\n",i,a1[i],a2[i],b1,b2,X[i],Y[i]);
		a.ins(a1[i]+(b1)*n,a2[i]+(b2)*n);a.ins(a2[i]+(b2^1)*n,a1[i]+(b1^1)*n);
	}
//	rep(1,d,i)printf("%d ",lis[i]);puts(":");
//	rep(1,n<<1,i)grep(a,i,j)printf("%d %d\n",i,a.des[j]);
	rep(1,n<<1,i)if(!t[i].dfn)dep=0,tarjan(i);rep(1,n,i)if(t[i].scc==t[i+n].scc)return;
	rep(1,n,i)ans[i]=(typ[i]+(t[i].scc>t[i+n].scc)+1)%3;got=1;
}
inline void dfs(int cur)
{
	if(cur==d+1){Solve();return;}
	lis[cur]=0;dfs(cur+1);if(got)return;
	lis[cur]=1;dfs(cur+1);
}
int main()
{
	n=read(),d=read(),scanf("%s",ch+1),m=read();
	rep(1,n,i)typ[i]=(ch[i]=='x'?loc[++q]=i:(ch[i]-'a'));
	rep(1,m,i)a1[i]=read(),X[i]=Get(),a2[i]=read(),Y[i]=Get();
	dfs(1);if(!got){puts("-1");return 0;}rep(1,n,i)putchar(ans[i]+'A');
}
